INSERT INTO questions (topic_id, enunciado, alt_a, alt_b, alt_c, alt_d, alt_e, gabarito, tipo, estilo_idecan, dificuldade, comentario_json, tags) VALUES ((SELECT id FROM topics WHERE nome = 'CTB_processo_administrativo' LIMIT 1), 'Sobre o auto de infração de trânsito, analise as afirmativas:

I. Deve conter a tipificação da infração e o local, a data e a hora do cometimento.
II. Deve identificar a placa, a marca e a espécie do veículo, entre outros elementos necessários.
III. A assinatura do infrator é indispensável para a validade do auto de infração.

Está CORRETO o que se afirma em:', 'Está correto o que se afirma em I, apenas.', 'Está correto o que se afirma em I e II, apenas.', 'Está correto o que se afirma em II e III, apenas.', 'Está correto o que se afirma em I, II e III.', NULL, 'B', 'assertivas', 'assertivas', 3, '{"o_que_testa":"Conteúdo obrigatório do auto de infração e natureza da assinatura do infrator (art. 280).","fundamento_legal":"CTB, art. 280: o auto de infração deve conter tipificação (I), local, data e hora (II), caracteres da placa, marca e espécie do veículo (III), entre outros. VI: assinatura do infrator, sempre que possível, valendo como notificação.","passo_a_passo":["I: Correta — incisos I e II do art. 280.","II: Correta — inciso III do art. 280.","III: Errada — assinatura é exigida sempre que possível, não é indispensável em qualquer caso.","Gabarito: I e II = alternativa B."],"pegadinha":"Transformar ''sempre que possível'' em ''indispensável'' — pegadinha frequente em processo administrativo de trânsito.","macete":"Auto completo (art. 280) + assinatura quando possível, não obrigatória em todo caso.","estudo_reverso":["CTB art. 280","CTB art. 281","CTB art. 281-A"]}'::jsonb, '{"autuacao","art_280","processo_administrativo"}'::text[]);